      "content": [
        {
          "type": "section_title",
          "arabic": "أمثلة على التقدير باستخدام المشتقة",
          "english": "Examples of Approximation using the Derivative"
        },
        {
          "type": "problem",
          "id": "b",
          "arabic_title": "تقريب قيمة $\\sqrt[3]{7.8}$",
          "english_title": "Approximating the value of $\\sqrt[3]{7.8}$",
          "details": {
            "function": "$f(x) = \\sqrt[3]{x} = x^{\\\\frac{1}{3}}$",
            "derivative": "$f'(x) = \\frac{1}{3}x^{-\\\\frac{2}{3}} = \\frac{1}{3\\sqrt[3]{x^2}}$",
            "approximation_parameters": {
              "b": "$7.8$",
              "a": "$8$",
              "h": "$-0.2$"
            },
            "steps": [
              {
                "description": "Calculate $f(a)$:",
                "equation": "$f(8) = \\sqrt[3]{8} = 2$"
              },
              {
                "description": "Calculate $f'(a)$:",
                "equation": "$f'(8) = \\frac{1}{3\\sqrt[3]{8^2}} = \\frac{1}{3(4)} = \\frac{1}{12} \\approx 0.083$"
              },
              {
                "description": "Apply approximation formula $f(a+h) \\approx f(a) + hf'(a)$:",
                "equation": "$f(7.8) \\approx f(8) + (-0.2)f'(8) = 2 - (0.2)(0.083)$"
              },
              {
                "description": "Result:",
                "equation": "$= 2 - 0.0166 = 1.9834$"
              },
              {
                "description": "Conclusion:",
                "equation": "$\\therefore \\sqrt[3]{7.8} \\approx 1.9834$"
              }
            ]
          }
        },
        {
          "type": "problem",
          "id": "c",
          "arabic_title": "تقريب قيمة $\\sqrt{17} + \\sqrt[4]{17}$",
          "english_title": "Approximating the value of $\\sqrt{17} + \\sqrt[4]{17}$",
          "details": {
            "function": "$f(x) = \\sqrt{x} + \\sqrt[4]{x} = x^{\\\\frac{1}{2}} + x^{\\\\frac{1}{4}}$",
            "derivative": "$f'(x) = \\frac{1}{2}x^{-\\\\frac{1}{2}} + \\frac{1}{4}x^{-\\\\frac{3}{4}}$",
            "approximation_parameters": {
              "b": "$17$",
              "a": "$16$",
              "h": "$1$"
            },
            "steps_part_1": [
              {
                "description": "Calculate $f(a)$:",
                "equation": "$f(16) = (16)^{\\\\frac{1}{2}} + (16)^{\\\\frac{1}{4}} = 4 + 2 = 6$"
              }
            ]
          }
        }
      ]
    },
    {
      "page_number": 111,
      "content": [
        {
          "type": "problem_continuation",
          "id": "c",
          "arabic_title": "تقريب قيمة $\\sqrt{17} + \\sqrt[4]{17}$ (تكملة)",
          "english_title": "Approximating the value of $\\sqrt{17} + \\sqrt[4]{17}$ (continued)",
          "details": {
            "steps_part_2": [
              {
                "description": "Calculate $f'(a)$:",
                "equation": "$f'(16) = \\frac{1}{2}(2^4)^{-\\\\frac{1}{2}} + \\frac{1}{4}(2^4)^{-\\\\frac{3}{4}} = \\frac{1}{2}(2^{-2}) + \\frac{1}{4}(2^{-3}) = 0.5(\\frac{1}{4}) + 0.25(\\frac{1}{8}) = 0.125 + 0.031 = 0.156$"
              },
              {
                "description": "Apply approximation formula $f(a+h) \\approx f(a) + hf'(a)$:",
                "equation": "$f(17) \\approx f(16) + (1)f'(16)$"
              },
              {
                "description": "Result:",
                "equation": "$f(17) \\approx 6 + (1)(0.156) = 6.156$"
              },
              {
                "description": "Conclusion:",
                "equation": "$\\therefore \\sqrt{17} + \\sqrt[4]{17} \\approx 6.156$"
              }
            ]
          }
        },
        {
          "type": "problem",
          "id": "d",
          "arabic_title": "تقريب قيمة $\\sqrt[3]{0.12}$",
          "english_title": "Approximating the value of $\\sqrt[3]{0.12}$",
          "details": {
            "function": "$f(x) = \\sqrt[3]{x} = x^{\\\\frac{1}{3}}$",
            "derivative": "$f'(x) = \\frac{1}{3}x^{-\\\\frac{2}{3}}$",
            "approximation_parameters": {
              "b": "$0.120$",
              "a": "$0.125$",
              "h": "$-0.005$"
            },
            "steps": [
              {
                "description": "Calculate $f(a)$:",
                "equation": "$f(0.125) = (0.5^3)^{\\\\frac{1}{3}} = 0.5$"
              },
              {
                "description": "Calculate $f'(a)$:",
                "equation": "$f'(0.125) = \\frac{1}{3}[(0.5)^3]^{-\\\\frac{2}{3}} = \\frac{1}{3}(0.5^{-2}) = \\frac{1}{3}(\\frac{1}{0.25}) = \\frac{4}{3} \\approx 1.333$"
              },
              {
                "description": "Apply approximation formula $f(a+h) \\approx f(a) + hf'(a)$:",
                "equation": "$f(0.12) \\approx f(0.125) + (-0.005)f'(0.125)$"
              },
              {
                "description": "Result:",
                "equation": "$f(0.12) \\approx 0.5 - 0.005(1.333) = 0.5 - 0.006665 = 0.493335$"
              },
              {
                "description": "Conclusion:",
                "equation": "$\\therefore \\sqrt[3]{0.12} \\approx 0.493335$"
              }
            ]
          }
        }
      ]
    },
